const topics = [
  "standardised testing", "mental health", "creativity", "screen time",
  "peer pressure", "teacher burnout", "university debt", "learning differences",
  "bullying", "curriculum relevance", "parental influence",
  "identity development", "critical thinking", "school anxiety", "gifted children",
  "special needs", "exam pressure", "school uniforms", "early years education",
  "school meals", "physical education", "art and music cuts", "reading habits",
  "sleep deprivation", "social media in schools", "parental pressure"
];

const staticData = $getWorkflowStaticData('global');

if (!staticData.usedTopics) {
  staticData.usedTopics = [];
}

if (staticData.usedTopics.length >= topics.length - 3) {
  staticData.usedTopics = [];
}

const available = topics.filter(t => !staticData.usedTopics.includes(t));
const shuffled = available.sort(() => Math.random() - 0.5);
const todayTopics = shuffled.slice(0, 3);

staticData.usedTopics = [...staticData.usedTopics, ...todayTopics];

return [{ json: { 
  topic1: todayTopics[0], 
  topic2: todayTopics[1], 
  topic3: todayTopics[2] 
}}];

